from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
from datetime import datetime

app = Flask(__name__)

# Configure MongoDB connection
app.config["MONGO_URI"] = "mongodb://localhost:27017/cms_db"
client = MongoClient(app.config["MONGO_URI"])
db = client.cms_db

# Collections
users_collection = db.users
documents_collection = db.documents

# --- User Profile Endpoints ---

@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.json
    if not user_data or not user_data.get('username') or not user_data.get('email'):
        return jsonify({"error": "Username and email are required"}), 400

    if users_collection.find_one({"username": user_data['username']}):
        return jsonify({"error": "Username already exists"}), 409

    if users_collection.find_one({"email": user_data['email']}):
        return jsonify({"error": "Email already exists"}), 409

    user_data['created_at'] = datetime.utcnow()
    user_id = users_collection.insert_one(user_data).inserted_id
    user_data['_id'] = str(user_id)
    return jsonify({"message": "User created successfully", "user": user_data}), 201

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({"_id": ObjectId(user_id)})
        if user:
            user['_id'] = str(user['_id'])
            return jsonify(user), 200
        return jsonify({"error": "User not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    update_data = request.json
    if not update_data:
        return jsonify({"error": "No data provided for update"}), 400

    try:
        # Prevent updating unique fields to existing values
        if 'username' in update_data and users_collection.find_one({"username": update_data['username'], "_id": {"$ne": ObjectId(user_id)}}):
            return jsonify({"error": "Username already taken by another user"}), 409
        if 'email' in update_data and users_collection.find_one({"email": update_data['email'], "_id": {"$ne": ObjectId(user_id)}}):
            return jsonify({"error": "Email already taken by another user"}), 409

        result = users_collection.update_one({"_id": ObjectId(user_id)}, {"$set": update_data})
        if result.matched_count == 0:
            return jsonify({"error": "User not found"}), 404
        
        user = users_collection.find_one({"_id": ObjectId(user_id)})
        user['_id'] = str(user['_id'])
        return jsonify({"message": "User updated successfully", "user": user}), 200
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

@app.route('/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = users_collection.delete_one({"_id": ObjectId(user_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "User not found"}), 404
        return jsonify({"message": "User deleted successfully"}), 200
    except Exception:
        return jsonify({"error": "Invalid User ID format"}), 400

# --- Document Endpoints ---

@app.route('/documents', methods=['POST'])
def create_document():
    doc_data = request.json
    if not doc_data or not doc_data.get('title') or not doc_data.get('content') or not doc_data.get('author_id'):
        return jsonify({"error": "Title, content, and author_id are required"}), 400

    # Check if author exists
    try:
        author = users_collection.find_one({"_id": ObjectId(doc_data['author_id'])})
        if not author:
            return jsonify({"error": "Author not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid Author ID format"}), 400

    doc_data['created_at'] = datetime.utcnow()
    doc_data['updated_at'] = datetime.utcnow()
    doc_data['tags'] = doc_data.get('tags', []) # Ensure tags is a list

    doc_id = documents_collection.insert_one(doc_data).inserted_id
    doc_data['_id'] = str(doc_id)
    doc_data['author_id'] = str(doc_data['author_id']) # Convert ObjectId back to string for response
    return jsonify({"message": "Document created successfully", "document": doc_data}), 201

@app.route('/documents', methods=['GET'])
def get_documents():
    query = {}
    author_id = request.args.get('author_id')
    tag = request.args.get('tag')
    title_contains = request.args.get('title_contains')

    if author_id:
        try:
            query['author_id'] = ObjectId(author_id)
        except Exception:
            return jsonify({"error": "Invalid Author ID format"}), 400
    if tag:
        query['tags'] = tag
    if title_contains:
        query['title'] = {"$regex": title_contains, "$options": "i"} # Case-insensitive search

    documents = []
    for doc in documents_collection.find(query):
        doc['_id'] = str(doc['_id'])
        doc['author_id'] = str(doc['author_id'])
        documents.append(doc)
    return jsonify(documents), 200

@app.route('/documents/<document_id>', methods=['GET'])
def get_document(document_id):
    try:
        document = documents_collection.find_one({"_id": ObjectId(document_id)})
        if document:
            document['_id'] = str(document['_id'])
            document['author_id'] = str(document['author_id'])
            return jsonify(document), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid Document ID format"}), 400

@app.route('/documents/<document_id>', methods=['PUT'])
def update_document(document_id):
    update_data = request.json
    if not update_data:
        return jsonify({"error": "No data provided for update"}), 400

    # Ensure author_id, if present, is valid
    if 'author_id' in update_data:
        try:
            author = users_collection.find_one({"_id": ObjectId(update_data['author_id'])})
            if not author:
                return jsonify({"error": "Author not found"}), 404
            update_data['author_id'] = ObjectId(update_data['author_id']) # Convert to ObjectId for storage
        except Exception:
            return jsonify({"error": "Invalid Author ID format"}), 400

    update_data['updated_at'] = datetime.utcnow()

    try:
        result = documents_collection.update_one({"_id": ObjectId(document_id)}, {"$set": update_data})
        if result.matched_count == 0:
            return jsonify({"error": "Document not found"}), 404
        
        document = documents_collection.find_one({"_id": ObjectId(document_id)})
        document['_id'] = str(document['_id'])
        document['author_id'] = str(document['author_id'])
        return jsonify({"message": "Document updated successfully", "document": document}), 200
    except Exception:
        return jsonify({"error": "Invalid Document ID format"}), 400

@app.route('/documents/<document_id>', methods=['DELETE'])
def delete_document(document_id):
    try:
        result = documents_collection.delete_one({"_id": ObjectId(document_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "Document not found"}), 404
        return jsonify({"message": "Document deleted successfully"}), 200
    except Exception:
        return jsonify({"error": "Invalid Document ID format"}), 400

# --- Aggregation Pipelines ---

@app.route('/analytics/documents_by_author', methods=['GET'])
def documents_by_author():
    pipeline = [
        {"$group": {"_id": "$author_id", "count": {"$sum": 1}}},
        {"$lookup": {
            "from": "users",
            "localField": "_id",
            "foreignField": "_id",
            "as": "author_info"
        }},
        {"$unwind": "$author_info"},
        {"$project": {
            "_id": 0,
            "author_id": {"$toString": "$_id"},
            "author_username": "$author_info.username",
            "author_email": "$author_info.email",
            "document_count": "$count"
        }},
        {"$sort": {"document_count": -1}}
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

@app.route('/analytics/documents_by_tag', methods=['GET'])
def documents_by_tag():
    pipeline = [
        {"$unwind": "$tags"},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$project": {
            "_id": 0,
            "tag": "$_id",
            "document_count": "$count"
        }},
        {"$sort": {"document_count": -1}}
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

if __name__ == '__main__':
    # Initialize collections with unique indexes if they don't exist
    users_collection.create_index("username", unique=True)
    users_collection.create_index("email", unique=True)
    documents_collection.create_index("author_id")
    documents_collection.create_index("tags")

    app.run(debug=True)